// src/bounded-contexts/ordering/domain/aggregates/Order/Order.ts

export class Order {
  private readonly id: OrderId;
  private items: OrderItem[];
  private status: OrderStatus;
  private readonly events: DomainEvent[] = [];

  private constructor(id: OrderId, items: OrderItem[], status: OrderStatus) {
    if (items.length === 0) throw new DomainError('Order must have at least one item');
    this.id = id;
    this.items = items;
    this.status = status;
  }

  static create(customerId: CustomerId, items: OrderItem[]): Order {
    const order = new Order(OrderId.generate(), items, OrderStatus.PENDING);
    order.events.push(new OrderCreated(order.id, customerId));
    return order;
  }

  static reconstitute(id: OrderId, items: OrderItem[], status: OrderStatus): Order {
    return new Order(id, items, status);
  }

  place(): void {
    this.assertStatus(OrderStatus.PENDING, 'place');
    this.status = OrderStatus.PLACED;
    this.events.push(new OrderPlaced(this.id));
  }

  ship(trackingId: TrackingId): void {
    this.assertStatus(OrderStatus.PLACED, 'ship');
    this.status = OrderStatus.SHIPPED;
    this.events.push(new OrderShipped(this.id, trackingId));
  }

  // Access child entities only through root — never expose them directly
  getItemCount(): number { return this.items.length; }
  getTotal(): Money { return this.items.reduce((s, i) => s.add(i.subtotal), Money.zero()); }

  pullEvents(): DomainEvent[] {
    const evts = [...this.events];
    this.events.length = 0;
    return evts;
  }

  private assertStatus(expected: OrderStatus, operation: string): void {
    if (this.status !== expected) {
      throw new DomainError(`Cannot ${operation} order in status ${this.status}`);
    }
  }
}

// src/bounded-contexts/ordering/domain/events/OrderPlaced.ts

export class OrderPlaced implements DomainEvent {
  readonly eventName = 'OrderPlaced';
  readonly occurredOn: Date;

  constructor(
    readonly orderId: OrderId,
    readonly customerId: CustomerId,
    readonly total: Money,
  ) {
    this.occurredOn = new Date();
  }
}

// src/bounded-contexts/ordering/application/commands/PlaceOrder.ts

export class PlaceOrderHandler {
  constructor(
    private readonly orderRepository: IOrderRepository,
    private readonly eventPublisher: IEventPublisher,
  ) {}

  async handle(command: PlaceOrderCommand): Promise<void> {
    const order = await this.orderRepository.findById(command.orderId);
    if (!order) throw new OrderNotFoundError(command.orderId);

    order.place();
    await this.orderRepository.save(order);

    const events = order.pullEvents();
    await this.eventPublisher.publishAll(events);
  }
}

// BAD: two aggregates in one transaction
async function placeOrder(orderId: string, inventoryId: string) {
  await db.transaction(async (tx) => {
    const order = await orderRepo.findById(orderId, tx);
    const inventory = await inventoryRepo.findById(inventoryId, tx);
    order.place();
    inventory.reserve(order.getItemCount()); // WRONG: cross-aggregate transaction
    await orderRepo.save(order, tx);
    await inventoryRepo.save(inventory, tx);
  });
}
